#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  $exe=".exe"
}
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/../.deno/supabase@2.89.1/node_modules/supabase/bin/supabase.exe"   $args
  } else {
    & "$basedir/../.deno/supabase@2.89.1/node_modules/supabase/bin/supabase.exe"   $args
  }
exit $LASTEXITCODE
